	scanf("%s",ch+1);

	int n=strlen(ch+1);

	for(int i=1;i<=n;i++) a[i]=ch[i]-'a';

	for(int i=1;i<=n;i++) a[i+n]=a[i];

	scanf("%s",ch+1);

	int m=strlen(ch+1);

	for(int i=1;i<=m;i++) b[i]=ch[i]-'a';

	for(int i=1;i<=n;i++) vis[a[i]]=1;

	int flag=0;

	for(int i=1;i<=m;i++) if(!vis[b[i]]) flag=1;

	if(flag) {

		puts("-1");

		return 0;

	}

	for(int i=2*n;i;i--) {

		for(int j=0;j<26;j++) f[i][j]=f[i+1][j];

		f[i][a[i]]=i;

	}

	int cnt=0,now=0;

	for(int i=1;i<=m;i++) {

		now++;

		while(now>n) cnt++,now-=n;

		now=f[now][b[i]];

	}

	cout<<1ll*cnt*n+now<<endl;

}

